import sys

class Node:
    def __init__(self, data=None):
        self.data = data
        self.next = None

class Solution:
    def __init__(self):
        self.head = None
        self.tail = None
        self.size = 0

    def enqueue(self, x: int) -> None:
        node = Node(x)
        if self.tail is None:
            self.head = node
            self.tail = node
        else:
            self.tail.next = node
            self.tail = node
        self.size += 1

    def dequeue(self) -> int:
        if self.head is None:
            return -1
        else:
            data = self.head.data
            self.head = self.head.next
            if self.head is None:
                self.tail = None
            self.size -= 1
            return data

    def getFront(self) -> int:
        if self.head is None:
            return -1
        else:
            return self.head.data

    def getSize(self) -> int:
        return self.size

