#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class Node {
public:
    int data;
    Node* next;

    Node(int data) {
        this->data = data;
        this->next = nullptr;
    }
};

class Solution {
private:
    Node* head;
    Node* tail;
    int size;

public:
    Solution() : head(nullptr), tail(nullptr), size(0) {}

    void enqueue(int x) {
        Node* node = new Node(x);
        if (tail == nullptr) {
            head = node;
            tail = node;
        } else {
            tail->next = node;
            tail = node;
        }
        size++;
    }

    int dequeue() {
        if (head == nullptr) {
            return -1;
        } else {
            int data = head->data;
            Node* temp = head;
            head = head->next;
            if (head == nullptr) {
                tail = nullptr;
            }
            delete temp;
            size--;
            return data;
        }
    }

    int getFront() {
        if (head == nullptr) {
            return -1;
        } else {
            return head->data;
        }
    }

    int getSize() {
        return size;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int Q;
    if (!(cin >> Q)) return 0;
    Solution sol;
    for (int i = 0; i < Q; i++) {
        string command;
        if (!(cin >> command)) return 0;
        if (command == "ENQUEUE") {
            int x;
            if (!(cin >> x)) return 0;
            sol.enqueue(x);
        } else if (command == "DEQUEUE") {
            cout << sol.dequeue() << "\n";
        } else if (command == "FRONT") {
            cout << sol.getFront() << "\n";
        } else if (command == "SIZE") {
            cout << sol.getSize() << "\n";
        } else if (command == "EXIT") {
            break;
        }
    }
    return 0;
}
